    private static readonly FrozenDictionary<int, char> ExponentToSymbol =
        new Dictionary<int, char>
        {
            [3] = 'k', [6] = 'M', [9] = 'G', [12] = 'T', [15] = 'P', [18] = 'E', [21] = 'Z', [24] = 'Y',
            [-3] = 'm', [-6] = 'μ', [-9] = 'n', [-12] = 'p', [-15] = 'f', [-18] = 'a', [-21] = 'z', [-24] = 'y',
        }.ToFrozenDictionary();

    // O(1) name→symbol lookup, replacing the O(n) Aggregate scan in ReplaceNameBySymbol
    private static readonly FrozenDictionary<string, char> NameToSymbol =
        UnitPrefixes.ToFrozenDictionary(kvp => kvp.Value.Name, kvp => kvp.Key);

    // Cached char→string conversions to avoid per-call allocations
    private static readonly FrozenDictionary<char, string> SymbolStrings =
        UnitPrefixes.Keys.ToFrozenDictionary(c => c, c => c.ToString());

    /// <summary>
