                return true;
            }
        }

        result = input;
        return false;
    }

    private static int GetExponentForSymbol(char symbol) =>
        symbol switch
        {
            'k' => 3, 'M' => 6, 'G' => 9, 'T' => 12, 'P' => 15, 'E' => 18, 'Z' => 21, 'Y' => 24,
